def is_valid_topological_order(graph: dict, order: list) -> bool:
    """
    Helper to verify if a result list satisfies topological ordering constraints.
    Returns True if for every edge u -> v, u appears before v in the order.
    """
    pos = {node: i for i, node in enumerate(order)}

    # Check that all nodes in the order are unique
    if len(pos) != len(order):
        return False

    for u, neighbors in graph.items():
        if u not in pos:
            return False
        for v in neighbors:
            if v not in pos or pos[u] >= pos[v]:
                return False
    return True


